/*
 * CPU Instruction Cycle Simulation in C
 * Demonstrates Basic Operational Concepts of Computer Organization
 * Implements Fetch, Decode, and Execute phases using CPU registers
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

// Define maximum memory size
#define MEMORY_SIZE 64
#define MAX_INSTRUCTION_LEN 20

// CPU Registers structure
typedef struct {
 int PC; // Program Counter - holds address of next instruction
 int IR; // Instruction Register - holds current instruction opcode
 int MAR; // Memory Address Register
 int MBR; // Memory Buffer Register (Memory Data Register)
 int ACC; // Accumulator - for arithmetic operations
 int operand; // Operand value from instruction
} CPURegisters;

// Memory structure
typedef struct {
 int data[MEMORY_SIZE];
} Memory;

// Initialize CPU registers
void initCPU(CPURegisters *cpu) {
 cpu->PC = 0;
 cpu->IR = 0;
 cpu->MAR = 0;
 cpu->MBR = 0;
 cpu->ACC = 0;
 cpu->operand = 0;
}

// Initialize memory
void initMemory(Memory *mem) {
 for (int i = 0; i < MEMORY_SIZE; i++) {
 mem->data[i] = 0;
 }
}

// Fetch phase: Get instruction from memory
void fetchPhase(CPURegisters *cpu, Memory *mem) {
 // Step 1: Transfer PC to MAR
 cpu->MAR = cpu->PC;

 // Step 2: Increment PC
 cpu->PC++;

 // Step 3: Read instruction from memory
 cpu->MBR = mem->data[cpu->MAR];

 // Step 4: Transfer to IR (we store opcode in IR)
 cpu->IR = cpu->MBR;

 printf("[FETCH] PC=%d -> MAR=%d, IR=%d\n", 
 cpu->PC - 1, cpu->MAR, cpu->IR);
}

// Decode phase: Interpret instruction
void decodePhase(CPURegisters *cpu, Memory *mem) {
 // Get operand from next memory location
 cpu->operand = mem->data[cpu->PC];

 // Increment PC past operand
 cpu->PC++;

 printf("[DECODE] IR=%d, Operand=%d\n", cpu->IR, cpu->operand);
}

// Execute phase: Perform the operation
int executePhase(CPURegisters *cpu, Memory *mem) {
 int halt = 0;

 switch (cpu->IR) {
 case 1: // LOAD: Load from memory to ACC
 cpu->MAR = cpu->operand;
 cpu->MBR = mem->data[cpu->MAR];
 cpu->ACC = cpu->MBR;
 printf("[EXECUTE] LOAD: ACC = %d\n", cpu->ACC);
 break;

 case 2: // STORE: Store ACC to memory
 cpu->MAR = cpu->operand;
 mem->data[cpu->MAR] = cpu->ACC;
 printf("[EXECUTE] STORE: Memory[%d] = %d\n", 
 cpu->MAR, cpu->ACC);
 break;

 case 3: // ADD: Add memory value to ACC
 cpu->MAR = cpu->operand;
 cpu->MBR = mem->data[cpu->MAR];
 cpu->ACC = cpu->ACC + cpu->MBR;
 printf("[EXECUTE] ADD: ACC = %d\n", cpu->ACC);
 break;

 case 4: // SUB: Subtract memory value from ACC
 cpu->MAR = cpu->operand;
 cpu->MBR = mem->data[cpu->MAR];
 cpu->ACC = cpu->ACC - cpu->MBR;
 printf("[EXECUTE] SUB: ACC = %d\n", cpu->ACC);
 break;

 case 99: // HALT
 printf("[EXECUTE] HALT: Program terminated\n");
 halt = 1;
 break;

 default:
 printf("[EXECUTE] Unknown opcode: %d\n", cpu->IR);
 halt = 1;
 }

 return halt;
}

// Main program execution
int main() {
 CPURegisters cpu;
 Memory mem;

 // Initialize CPU and Memory
 initCPU(&cpu);
 initMemory(&mem);

 // Load data into memory
 // Address 10, 11, 12 hold operand values
 mem.data[10] = 10; // First operand
 mem.data[11] = 15; // Second operand
 mem.data[12] = 5; // Third operand

 // Load program instructions at address 0
 // Format: [opcode, operand, opcode, operand, ...]
 // Opcode: 1=LOAD, 2=STORE, 3=ADD, 4=SUB, 99=HALT
 mem.data[0] = 1; // LOAD
 mem.data[1] = 10; // from address 10
 mem.data[2] = 3; // ADD
 mem.data[3] = 11; // with address 11
 mem.data[4] = 4; // SUB
 mem.data[5] = 12; // with address 12
 mem.data[6] = 2; // STORE
 mem.data[7] = 20; // to address 20
 mem.data[8] = 99; // HALT
 mem.data[9] = 0; // (not used)

 printf("======================================\n");
 printf("CPU Instruction Cycle Simulation\n");
 printf("======================================\n");
 printf("Program: (10 + 15 - 5)\n\n");

 // Execute instruction cycle
 while (1) {
 printf("\n--- Cycle: PC=%d ---\n", cpu.PC);

 // Fetch
 fetchPhase(&cpu, &mem);

 // Check for HALT
 if (cpu.IR == 99) {
 printf("[EXECUTE] HALT\n");
 break;
 }

 // Decode
 decodePhase(&cpu, &mem);

 // Execute
 if (executePhase(&cpu, &mem)) {
 break;
 }
 }

 printf("\n======================================\n");
 printf("Final ACC Value: %d\n", cpu.ACC);
 printf("Memory[20] Result: %d\n", mem.data[20]);
 printf("======================================\n");

 return 0;
}
